Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformSpecificTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformSpecificTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped on other OSes
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void WindowsRegistry_ReadsValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpu()
    {
        var result = GpuRenderer.Render();
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API: retry up to 3 times
    [TestMethod]
    [Retry(3)]
    public async Task GetWeather_ReturnsData()
    {
        var weather = await _weatherClient.GetAsync("London", _testContext.CancellationToken);
        Assert.IsNotNull(weather);
    }

    // 4. Cleanup temp files even on failure
    [TestMethod]
    public void ProcessFile_WritesOutput()
    {
        _tempFile = Path.GetTempFileName();
        File.WriteAllText(_tempFile, "test data");

        var result = FileProcessor.Process(_tempFile);

        Assert.IsTrue(File.Exists(result.OutputPath));
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Runs even if the test fails
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Summary of attributes:**

| Scenario | Attribute/Pattern |
|----------|-------------------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` |
| Flaky external API | `[Retry(3)]` |
| Cleanup on failure | `[TestCleanup]` method |

**Key notes:**
- `[OSCondition]` and `[CICondition]` require MSTest 3.10+
- `[Retry]` requires MSTest 3.9+ — use only for genuine external flakiness, not race conditions
- `[TestCleanup]` always runs after each test (pass or fail), before `Dispose`
